import React, { useEffect, useState } from "react";
import { Card, Button, Modal } from "antd";
import { useDispatch, useSelector } from "react-redux";
import { Link, useNavigate } from "react-router-dom"; // useNavigate instead of useHistory
import { BiCart } from "react-icons/bi";
import { config } from "../../utils/axiosconfig";
import { getOrders } from "../../features/auth/authSlice";


const NewOrders = () => {
  const dispatch = useDispatch();
  const navigate = useNavigate(); // useNavigate hook
  const [isDetailModalVisible, setIsDetailModalVisible] = useState(false);
  

  useEffect(() => {
    dispatch(getOrders(config));
  }, [dispatch]);

  const orderState = useSelector((state) => state?.auth?.orders?.orders);
 
   const user = useSelector((state) => state?.auth?.user);
  const filteredOrders = orderState?.filter(
    (order) =>
      order?.cart?.some((item) => item.postedByUserId === user?._id)
  );
 

  const handleViewOrder = (orderId) => {
    navigate(`${orderId}`); 
  };

  return (
    <div className="notifications">
      <h3 className="mb-4 title">Order Notifications</h3>
      {filteredOrders?.length === 0 ? (
        <div style={{ textAlign: 'center', marginTop: '20px' }}>
          <BiCart size={50} style={{ color: 'gray' }} />
          <p>No new orders here</p>
        </div>
      ) : (
          filteredOrders?.map((order, index) => (
          <Card
            key={index}
            title={`Order #${index + 1}`}
            className="notification-card"
            > 
              <h2 className="relative -top-28 -right-96"><span className="text-gray-950 font-extrabold">Status:</span> <span className=" bg-red-500 text-gray-50 p-2 rounded-md">{order?.orderStatus}</span></h2>
            <p>
              <strong>Customer:</strong> {order?.user?.firstname} {order?.user?.lastname}
            </p>
            <p>
              <strong>Products:</strong>{" "}
              {order?.cart?.map((product) => (
                <Link
                  key={product.product_id}
                  to={`${product.product_id}`}
                  className="text-blue-500 hover:underline"
                >
                  {product.name}
                </Link>
              ))}
            </p>
            <p>
              <strong>Amount:</strong> ${order?.totalPrice.toFixed(2)}
            </p>
            <p>
              <strong>Date:</strong> {new Date(order?.createdAt).toLocaleString()}
            </p>
            <div className="actions">
              <Button
                type="primary"
                onClick={() => handleViewOrder(order._id)}
                className="me-2"
              >
                View Detailed Order
              </Button>
            </div>
          </Card>
        ))
      )}

      

      <Modal
        title="Order Details"
        visible={isDetailModalVisible}
        onCancel={() => setIsDetailModalVisible(false)}
        footer={null}
      >
        {/* Detailed Order Information goes here */}
        <p>More order details here...</p>
      </Modal>
    </div>
  );
};

export default NewOrders;
